package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormatWithNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormatWithEmptyValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormatWithNullValues() throws IOException {
        String result = csvFormat.format((Object) null, "test", null);
        assertEquals(",test,", result);
    }

    @Test
    void testFormatThrowsIllegalStateExceptionOnIOException() throws Exception {
        // Create a spy CSVPrinter that throws IOException on printRecord
        CSVPrinter spyPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("mocked IO exception")).when(spyPrinter).printRecord((Object[]) any());
        doNothing().when(spyPrinter).close();

        // Use reflection to invoke the private constructor of CSVFormat
        CSVFormat format;
        try {
            Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, Class.forName("org.apache.commons.csv.CSVFormat$QuoteMode"),
                Character.class, Character.class, boolean.class, boolean.class,
                String.class, String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
            constructor.setAccessible(true);
            // Passing null for QuoteMode parameter
            format = constructor.newInstance(',', '"', null, null, null, false, true, "\r\n",
                    null, null, null, false, false, false, false, false);
        } catch (ReflectiveOperationException e) {
            throw new RuntimeException(e);
        }

        // Use reflection to replace CSVPrinter constructor to return our spy
        Constructor<CSVPrinter> printerConstructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        printerConstructor.setAccessible(true);

        // Create a subclass of CSVFormat to override print method to return our spyPrinter
        CSVFormat formatWithSpyPrinter = new CSVFormat(format.getDelimiter(), format.getQuoteCharacter(), format.getQuoteMode(),
                format.getCommentMarker(), format.getEscapeCharacter(), format.getIgnoreSurroundingSpaces(),
                format.getIgnoreEmptyLines(), format.getRecordSeparator(), format.getNullString(),
                format.getHeaderComments(), format.getHeader(), format.getSkipHeaderRecord(),
                format.getAllowMissingColumnNames(), format.getIgnoreHeaderCase(), format.getTrim(),
                format.getTrailingDelimiter()) {
            @Override
            public CSVPrinter print(final Appendable out) throws IOException {
                return spyPrinter;
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> formatWithSpyPrinter.format("x"));
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("mocked IO exception", thrown.getCause().getMessage());
    }
}
